import React, { useState, useEffect } from 'react';
import Login from './pages/Login';
import FloorSelection from './pages/FloorSelection';
import RoomList from './pages/RoomList';
import RoomDetail from './pages/RoomDetail';
import AdminPanel from './pages/AdminPanel';
import ExpiryList from './pages/ExpiryList';
import Header from './components/Header';
import { ALL_ROOMS } from './data/roomsData';
import './styles/main.css';
import './styles/inventory.css';

function App() {
    // --- СОСТОЯНИЯ (STATES) ---
    const [user, setUser] = useState(null);
    const [screen, setScreen] = useState('login');
    const [selectedFloor, setSelectedFloor] = useState(null);
    const [selectedRoom, setSelectedRoom] = useState(null);

    // Основная база данных номеров
    const [rooms, setRooms] = useState(() => {
        const saved = localStorage.getItem('hotel_rooms');
        return saved ? JSON.parse(saved) : ALL_ROOMS;
    });

    // Архив отчетов (за прошлые дни)
    const [archive, setArchive] = useState(() => {
        const saved = localStorage.getItem('hotel_archive');
        return saved ? JSON.parse(saved) : [];
    });

    // Логи действий за СЕГОДНЯ
    const [dailyLogs, setDailyLogs] = useState(() => {
        const saved = localStorage.getItem('hotel_logs');
        return saved ? JSON.parse(saved) : [];
    });

    const [expiryThreshold, setExpiryThreshold] = useState(90);

    // --- ЛОГИКА 00:00 (СБРОС И АРХИВАЦИЯ) ---
    useEffect(() => {
        const checkMidnight = () => {
            const lastActiveDate = localStorage.getItem('last_active_date');
            const today = new Date().toLocaleDateString();

            if (lastActiveDate && lastActiveDate !== today) {
                // 1. Формируем отчет за прошедший день для архива
                const dailyReport = {
                    date: lastActiveDate,
                    logs: dailyLogs,
                    stats: {
                        checked: rooms.filter(r => r.status === 'checked').length,
                        dnd: rooms.filter(r => r.status === 'dnd').length
                    }
                };

                // 2. Сохраняем в архив
                const updatedArchive = [dailyReport, ...archive];
                setArchive(updatedArchive);
                localStorage.setItem('hotel_archive', JSON.stringify(updatedArchive));

                // 3. Сбрасываем номера (делаем серыми) и удаляем заметки
                const resetRooms = rooms.map(r => ({
                    ...r,
                    status: 'unchecked',
                    notes: ''
                }));
                setRooms(resetRooms);
                setDailyLogs([]); // Чистим логи для нового дня

                localStorage.setItem('hotel_rooms', JSON.stringify(resetRooms));
                localStorage.setItem('hotel_logs', JSON.stringify([]));
            }
            localStorage.setItem('last_active_date', today);
        };

        checkMidnight();
    }, [rooms, archive, dailyLogs]);

    // --- СОХРАНЕНИЕ В LOCALSTORAGE ПРИ ЛЮБОМ ИЗМЕНЕНИИ ---
    useEffect(() => {
        localStorage.setItem('hotel_rooms', JSON.stringify(rooms));
        localStorage.setItem('hotel_logs', JSON.stringify(dailyLogs));
    }, [rooms, dailyLogs]);


    // --- ОБРАБОТЧИКИ (HANDLERS) ---
    const handleLogout = () => {
        setUser(null);
        setScreen('login');
    };

    const handleSaveRoom = (updatedRoom) => {
        // Записываем действие в лог
        const newLog = {
            time: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
            staff: user.login,
            roomId: updatedRoom.id,
            action: updatedRoom.status === 'checked' ? 'Проверка/Пополнение' : 'Отказ (DND)'
        };

        setDailyLogs([newLog, ...dailyLogs]);

        // Обновляем состояние комнат
        const newRooms = rooms.map(r => r.id === updatedRoom.id ? updatedRoom : r);
        setRooms(newRooms);
        setScreen('rooms');
    };

    // --- РЕНДЕР (ЭКРАНЫ) ---
    if (!user) {
        return <Login onLogin={(userData) => { setUser(userData); setScreen('floors'); }} />;
    }

    return (
        <div className="app-container">
            <Header
                user={user}
                onLogout={handleLogout}
                onBack={() => setScreen(screen === 'detail' ? 'rooms' : 'floors')}
                showBack={screen !== 'floors'}
            />

            {screen === 'floors' && (
                <FloorSelection
                    onSelectFloor={(floor) => { setSelectedFloor(floor); setScreen('rooms'); }}
                    onShowExpiry={() => setScreen('expiry')}
                    onOpenAdmin={() => setScreen('admin')}
                    role={user.role}
                />
            )}

            {screen === 'rooms' && (
                <RoomList
                    floor={selectedFloor}
                    rooms={rooms}
                    onSelectRoom={(room) => { setSelectedRoom(room); setScreen('detail'); }}
                />
            )}

            {screen === 'detail' && (
                <RoomDetail
                    room={selectedRoom}
                    user={user}
                    onSave={handleSaveRoom}
                />
            )}

            {screen === 'admin' && (
                <AdminPanel
                    rooms={rooms}
                    archive={archive}
                    dailyLogs={dailyLogs}
                    threshold={expiryThreshold}
                    setThreshold={setExpiryThreshold}
                    // Здесь можно будет добавить функции управления персоналом
                />
            )}

            {screen === 'expiry' && (
                <ExpiryList rooms={rooms} threshold={expiryThreshold} />
            )}
        </div>
    );
}

export default App;
